rap-bopf-029.codeExamples:
" RAP Leave Request — Complete Structure
@AbapCatalog.sqlViewName: 'ZV_LEAVEREQ'
@AccessControl.authorizationCheck: #NOT_REQUIRED
@EndUserText.label: 'Leave Request'
define root view entity ZRAP_LeaveRequest
  as select from zleave_request
{
  key request_id     as RequestId,
      employee_id    as EmployeeId,
      leave_type     as LeaveType,
      start_date     as StartDate,
      end_date       as EndDate,
      leave_days     as LeaveDays,
      status         as Status,
      reject_reason  as RejectReason
}
" Behavior Definition
managed implementation in class ZBP_LeaveRequest unique;
define behavior for ZRAP_LeaveRequest alias LeaveRequest
persistent table zleave_request
lock master
draft table zdt_leavereq
{
  create; update;
  field ( mandatory ) EmployeeId, LeaveType, StartDate, EndDate;
  field ( readonly )  RequestId, LeaveDays, Status;
  validation validateDateRange on save { field StartDate, EndDate; }
  determination calcLeaveDays on modify { field StartDate, EndDate; }
  action approve result [1] $self;
  action reject result [1] $self;
}

rap-bopf-031.codeExamples:
" FS to TS Conversion — Leave Request Example
" FS: 'Employee submits leave request, manager approves'

" TS: CDS Entity (Data Model)
define root view entity ZRAP_LeaveRequest
  as select from zleave_request
{
  key request_id   as RequestId,    " System generated
      employee_id  as EmployeeId,   " FS: employee
      leave_type   as LeaveType,    " FS: leave type
      start_date   as StartDate,    " FS: start date
      end_date     as EndDate,      " FS: end date
      leave_days   as LeaveDays,    " FS: auto-calculated
      status       as Status,       " FS: status track
      reject_rsn   as RejectReason  " FS: rejection comment
}
" TS: Behavior Definition
managed implementation in class ZBP_LeaveRequest unique;
define behavior for ZRAP_LeaveRequest alias LeaveRequest
persistent table zleave_request lock master draft table zdt_lr
{
  create; update;  " FS: employee submits
  field ( mandatory ) EmployeeId, LeaveType, StartDate, EndDate;
  field ( readonly )  RequestId, LeaveDays, Status;
  validation validateDateRange  on save { field StartDate, EndDate; }
  validation validateBalance    on save { field LeaveType, StartDate, EndDate; }
  determination calcLeaveDays   on modify { field StartDate, EndDate; }
  action approve result [1] $self;  " FS: manager approves
  action reject  result [1] $self;  " FS: manager rejects
}

